import firebase from 'firebase'
import router from '../../routes/router';
import swal from 'sweetalert2';
import { getUserConf, updateUserConf, addDonation } from '../../dao/firestore';

const state = {
    user: null,
    conf: {
        experience: -1,
        initialCapital: 0,
        termsAccepted: false,
        view: {
            theme: 'blue',
            darkmode: true
        },
        cash: 0,
        history: [],
        positions: [],
        minimumVolume: 50000
    },
};

export default {
    namespaced: true,
    state,
    getters: {
        user: state => state.user,
        conf: state => state.conf,
        getPosition: state => isin => state.conf.positions.find(p => p.isin === isin),
    },
    mutations: {
        SET_USER (state, payload) {
            state.user = payload;
        },
        LOGOUT (state, payload) {
            state.user = null
        },
        UPDATE_USER_CONF(state, payload) {
            state.conf = payload;
        },
    },
    actions: {
        async autoSignIn({ commit }, payload) {
            const user = {
                ...payload.providerData[0], 
                uid: payload.uid, 
                creationTime: new Date(payload.metadata.creationTime)
            };
            commit('SET_USER', user)

            const userconf = await getUserConf(user);
            if( userconf && userconf.experience ) {
                // Add pro mode
                commit('UPDATE_USER_CONF', {
                    ...userconf,
                    isPro: userconf.proEoT && +(new Date()) < userconf.proEoT
                })
                // Update background
                document.body.classList[userconf.view.darkmode?'remove':'add']('white-content');
            }
            else router.push('/onboarding');
        },
        async signIn({ commit }, payload) {
            var provider = null;
            if(payload == 'Twitter') provider = new firebase.auth.TwitterAuthProvider()
            else if(payload == 'Google') provider = new firebase.auth.GoogleAuthProvider()
            
            const result = await firebase.auth().signInWithPopup(provider);
            var user = result.user;
            const userconf = await getUserConf(user);
            commit('SET_USER', user)
            
            if( userconf && userconf.experience ) {
                // Add pro mode
                commit('UPDATE_USER_CONF', {
                    ...userconf,
                    isPro: userconf.proEoT && +(new Date()) < userconf.proEoT
                })
                // Update background
                document.body.classList[userconf.view.darkmode?'remove':'add']('white-content');
                router.push('/dashboard'); 
            }
            else router.push('/onboarding');
        },
        logout({ commit }) {
            firebase.auth().signOut().then(function () {
                commit('LOGOUT')
                router.push('/login');
            }).catch(function (error) {
                alert(error)
                return
            });
        },
        async setPro({commit, state}, payload) {
            const newconf = {
                ...state.conf, 
                proEoT: payload.proEoT,
                isPro: +(new Date()) < payload.proEoT
            }
            await addDonation({
                assoName:payload.assoName, 
                donationValue: payload.donationValue,
                t: parseInt((+new Date())/1000)
            });
            await updateUserConf(state.user, newconf)
            commit('UPDATE_USER_CONF', newconf)
            swal("Merci.", "Vous pouvez maintenant découvrir les fonctionnalités pro !", 'success')
        },
        async createconf({commit, state}, payload) {
            const newconf = {...state.conf, ...payload}
            await updateUserConf(state.user, newconf)
            commit('UPDATE_USER_CONF', newconf)
            router.push('/dashboard');
        },
        async updateconf({commit, state}, payload) {
            const newconf = {...state.conf, ...payload}
            await updateUserConf(state.user, newconf)
            commit('UPDATE_USER_CONF', newconf)
        },
        async updatePosition({commit, state}, payload) {
            const positions = state.conf.positions;
            const index = positions.findIndex(p => p.isin === payload.isin);
            if(index != -1) {
                positions[index] = payload;
            }
            else positions.push(payload);
            
            const newconf = {...state.conf, positions}
            await updateUserConf(state.user, newconf)
            commit('UPDATE_USER_CONF', newconf)
        },
        async removePosition({commit, state}, isin) {
            const positions = state.conf.positions.filter(p => p.isin != isin);
            const newconf = {...state.conf, positions}
            await updateUserConf(state.user, newconf)
            commit('UPDATE_USER_CONF', newconf)
        },
    }
};