import db from '../firebaseConfig';
import { getWeekNumber } from '../util/dateTools';

/* User conf */
export async function getUserConf(user) {
    const result = await db.collection('userconfs').doc(user.uid).get();
    return result.exists ? result.data() : false;
}
export async function createUserConf(user, conf) {
    return db.collection('userconfs').doc(user.uid).set(conf);
}
export async function updateUserConf(user, conf) {
    let newConf = {...conf}
    delete newConf.isPro;
    if( ! (await getUserConf(user)) ) {
        return await createUserConf(user, newConf);
    }
    return db.collection('userconfs').doc(user.uid).update(newConf);
}

/* Donation */
export async function addDonation(donation) {
    return db.collection('donations').add(donation);
}

/* Quote History */
export async function getQuoteWeeklyHistory(instrument) {
    const snapshot = await db.collection('weekly').doc(instrument.isin).get();
    const document = snapshot.data();

    let quotes = document.d
    .sort( (a,b) => a.t - b.t)
    .map(q => [
        q.t*1000,
        q.o,
        q.h,
        q.l,
        q.c,
        q.v
    ]);
    // Add current value to graph
    let lastQuote = quotes[quotes.length-1];
    // Si on est la même semaine
    if(lastQuote && getWeekNumber(lastQuote[0]) === getWeekNumber(instrument.li.t*1000)
        && instrument.li.o && instrument.li.t*1000 > lastQuote[0]) {
        quotes[quotes.length-1] = [
            instrument.li.t*1000,
            lastQuote[1],
            lastQuote[2] > instrument.li.h ? lastQuote[2] : instrument.li.h,
            lastQuote[3] < instrument.li.l ? lastQuote[3] : instrument.li.l,
            instrument.li.last,
            lastQuote[5] + instrument.li.v
        ]
    } // Pas la même semaine (lundi en général)
    else if(lastQuote && getWeekNumber(lastQuote[0]) !== getWeekNumber(instrument.li.t*1000)
    && instrument.li.o && instrument.li.t*1000 > lastQuote[0] ){
        quotes.push([
            instrument.li.t*1000,
            instrument.li.o,
            instrument.li.h,
            instrument.li.l,
            instrument.li.last,
            instrument.li.v
        ]);
    }  
    return quotes;
}

export async function getQuoteDailyHistory(instrument) {
    const snapshot = await db.collection('daily').doc(instrument.isin).get();
    const document = snapshot.data();

    let quotes = document.d
    .sort( (a,b) => a.t - b.t)
    .map(q => [
        (q.t - q.t % (24 * 60 * 60) )*1000,
        q.o,
        q.h,
        q.l,
        q.c,
        q.v
    ]);
    // Add current value to graph
    let lastQuote = quotes[quotes.length-1];
    // Si on est le même jour
    const lastQuoteDate = new Date(lastQuote[0]);
    const currentQuoteDate = new Date(instrument.li.t*1000)
    const isSameDay = (lastQuoteDate.getDate() === currentQuoteDate.getDate() 
        && lastQuoteDate.getMonth() === currentQuoteDate.getMonth()
        && lastQuoteDate.getFullYear() === currentQuoteDate.getFullYear())

    if( !isSameDay && instrument.li.o ){
        quotes.push([
            instrument.li.t*1000,
            instrument.li.o,
            instrument.li.h,
            instrument.li.l,
            instrument.li.last,
            instrument.li.v
        ]);
    }  
    return quotes;
}